;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.ftm-log-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:20px}\n.ftm-log-item{display:flex;gap:16px;align-items:flex-start;background:#fff;border-radius:12px;padding:20px}\n.ftm-log-icon{width:40px;height:40px;border-radius:8px;background:rgba(180,83,9,0.1);display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.ftm-log-icon svg{stroke:#b45309}\n.ftm-log-item-label{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;color:#000864;margin-bottom:2px}\n.ftm-log-item-value{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#333;line-height:1.5}\n\n.et_pb_section .ftm-log-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .ftm-log-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .ftm-log-item-label,.et_pb_section .ftm-log-item-value{-webkit-font-smoothing:auto !important}\n\n@media(max-width:768px){\n  .ftm-log-grid{grid-template-columns:1fr}\n  .ftm-log-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.ftm-log-section *{transition:none !important}}\n/* === REGISTRATION CTA === */\n.ftm-reg-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:80px 24px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ftm-reg-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.ftm-reg-section>*{position:relative;z-index:2}\n.ftm-reg-section h2{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#fff;margin:0 0 16px;padding:0}\n.ftm-reg-meta{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.85);margin:0 0 32px;padding:0}\n.ftm-reg-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#fff;background:#b45309;padding:20px 48px;border-radius:12px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 20px rgba(180,83,9,0.4)}\n.ftm-reg-cta:hover{background:rgb(195,117,58);transform:translateY(-2px);box-shadow:0 8px 24px rgba(180,83,9,0.3)}\n.ftm-reg-secondary{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);margin-top:24px;padding:0}\n.ftm-reg-secondary a{color:#fff;text-decoration:underline;transition:color 0.3s ease}\n.ftm-reg-secondary a:hover{color:#fff}\n\n.et_pb_section .ftm-reg-section h2{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .ftm-reg-cta{-webkit-font-smoothing:auto !important;line-height:28.8px !important}\n.et_pb_section .ftm-reg-meta,.et_pb_section .ftm-reg-secondary{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n@media(max-width:768px){\n  .ftm-reg-section h2{font-size:32px}\n  .ftm-reg-cta{width:100%;justify-content:center;padding:16px 32px;font-size:16px}\n}\n@media(prefers-reduced-motion:reduce){.ftm-reg-section *{transition:none !important}}\n/* === RELATED EVENTS === */\n.ftm-rel-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ftm-rel-inner{max-width:1100px;margin:0 auto}\n.ftm-rel-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#b45309;margin-bottom:16px}\n.ftm-rel-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.ftm-rel-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.ftm-rel-card{background:#fff;border-radius:16px;overflow:hidden;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.ftm-rel-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.ftm-rel-card-border{height:4px}\n.ftm-rel-card-body{padding:28px}\n.ftm-rel-badge{display:inline-block;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;padding:4px 12px;border-radius:50px;margin-bottom:12px}\n.ftm-rel-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;line-height:1.4;margin:0 0 16px;padding:0}\n.ftm-rel-meta{display:flex;flex-direction:column;gap:8px;margin-bottom:16px}\n.ftm-rel-meta-item{display:flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80}\n.ftm-rel-meta-item svg{flex-shrink:0;stroke:#94a3b8}\n.ftm-rel-link{display:inline-flex;align-items:center;gap:4px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;text-decoration:none;transition:opacity 0.3s ease}\n.ftm-rel-link:hover{opacity:0.8}\n\n.et_pb_section .ftm-rel-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .ftm-rel-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .ftm-rel-card h3{-webkit-font-smoothing:auto !important;margin:0 0 16px !important;padding:0 !important}\n\n@media(max-width:768px){\n  .ftm-rel-grid{grid-template-columns:1fr}\n  .ftm-rel-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.ftm-rel-card{transition:none !important}}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero — Factory Tour MES (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero — Factory Tour MES (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero — Factory Tour MES (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-hero-section">\n  <div class="ftm-hero-superd" aria-hidden="true"></div>\n  <a href="/th/news/" class="ftm-hero-back">\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>\n    &larr; กลับไปข่าวสารและกิจกรรม\n  </a>\n  <span class="ftm-hero-badge">เยี่ยมชมโรงงาน</span>\n  <h1>ทัวร์โรงงานจริง: ดู DigiWin MES ทำงานจริง</h1>\n  <p class="ftm-hero-subtitle">เดินชมพื้นที่ผลิตของโรงงานจริงที่ใช้ DigiWin MES ดูว่าข้อมูลการผลิตไหลจากเครื่องจักรไปยังแดชบอร์ดผู้บริหารได้อย่างไรแบบเรียลไทม์</p>\n\n  <div class="ftm-hero-facts">\n    \n      <div class="ftm-hero-fact">\n        <div class="ftm-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n        </div>\n        <div class="ftm-hero-fact-value">8 พฤษภาคม 2026</div>\n        <div class="ftm-hero-fact-label">วันพฤหัสบดี</div>\n      </div>\n\n      <div class="ftm-hero-fact">\n        <div class="ftm-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n        </div>\n        <div class="ftm-hero-fact-value">10:00 – 15:00</div>\n        <div class="ftm-hero-fact-label">ครึ่งวัน</div>\n      </div>\n\n      <div class="ftm-hero-fact">\n        <div class="ftm-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n        </div>\n        <div class="ftm-hero-fact-value">EEC Industrial Zone</div>\n        <div class="ftm-hero-fact-label">ประเทศไทย</div>\n      </div>\n\n      <div class="ftm-hero-fact">\n        <div class="ftm-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4-4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87"/><path d="M16 3.13a4 4 0 010 7.75"/></svg>\n        </div>\n        <div class="ftm-hero-fact-value">20 ท่าน</div>\n        <div class="ftm-hero-fact-label">จำกัดจำนวนเพื่อความปลอดภัย</div>\n      </div>\n  </div>\n\n  <a href="#register" class="ftm-hero-cta">\n    ลงทะเบียนเยี่ยมชม\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n  </a>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problem — Factory Tour MES (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problem — Factory Tour MES (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problem — Factory Tour MES (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-prob-section">\n  <div class="ftm-prob-inner">\n    <span class="ftm-prob-label">ความท้าทาย</span>\n    <h2 class="ftm-prob-title">เห็นจริงถึงจะเชื่อ — ภาพหน้าจอแทนที่ความจริงบนพื้นที่ผลิตไม่ได้</h2>\n  </div>\n  <div class="ftm-prob-body">\n    \n    <p>ผู้ขายซอฟต์แวร์ทุกรายโชว์หน้าจอสาธิตที่สวยงาม แดชบอร์ดที่คัดเลือกมาอย่างดีพร้อมข้อมูลสมบูรณ์แบบ รันบนเซิร์ฟเวอร์สาธิตที่ไหนสักที่ ดำเนินการโดยวิศวกรฝ่ายขายที่รู้ดีว่าต้องกดปุ่มไหน ดูดีมากในห้องประชุม แต่สิ่งที่สำคัญคือระบบทำงานอย่างไรบนพื้นที่ผลิตจริง — กับเครื่องจักรจริง พนักงานจริง และปัญหาจริงที่เกิดขึ้นแบบเรียลไทม์</p>\n\n    <p>ช่องว่างระหว่างสภาพแวดล้อมสาธิตกับโรงงานจริงคือจุดที่การติดตั้ง MES ส่วนใหญ่ล้มเหลว พนักงานที่ใช้งานอินเทอร์เฟซไม่คล่อง ข้อมูลที่ไม่ไหลเพราะเซ็นเซอร์ตั้งค่าผิด รายงานที่ดูต่างออกไปเมื่อสร้างจากความวุ่นวายของการผลิตจริง ไม่ใช่ข้อมูลตัวอย่างที่สะอาด <strong>คุณประเมินสิ่งเหล่านี้จากห้องประชุมไม่ได้</strong></p>\n\n    <p>การเยี่ยมชมโรงงานครั้งนี้ให้คุณเข้าถึงแบบไม่มีกรอง เดินชมสายการผลิตและดูหน้าจอที่พนักงานใช้จริง — ไม่ใช่การสาธิตที่คัดมา ถามพนักงานโดยตรงเกี่ยวกับประสบการณ์ใช้งานระบบ ดูข้อมูลไหลแบบเรียลไทม์จากเครื่อง CNC ไปยังแดชบอร์ดผู้บริหาร นี่คือการตรวจสอบความจริงที่แยกการตัดสินใจที่มั่นใจออกจากการคาดเดาที่แพง</p>\n    \n    \n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes — Factory Tour MES (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes — Factory Tour MES (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes — Factory Tour MES (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-out-section">\n  <div class="ftm-out-inner">\n    <span class="ftm-out-label">ผลลัพธ์จากการเยี่ยมชม</span>\n    <h2 class="ftm-out-title">สิ่งที่คุณจะได้รับจากการเยี่ยมชมครั้งนี้</h2>\n    <div class="ftm-out-grid">\n      \n    <div class="ftm-out-card">\n      <div class="ftm-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M2 20h20M6 20V10l4-6h4l4 6v10"/><path d="M6 14h12"/></svg>\n      </div>\n      <h3>ดูการติดตั้ง MES จริงบนพื้นที่ผลิตจริง</h3>\n      <p>ไม่ใช่สภาพแวดล้อมสาธิต ไม่ใช่การจำลอง — โรงงานจริงที่มีออเดอร์ผลิตจริงรันผ่าน DigiWin MES อยู่ตอนนี้</p>\n    </div>\n\n    <div class="ftm-out-card">\n      <div class="ftm-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4-4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87"/><path d="M16 3.13a4 4 0 010 7.75"/></svg>\n      </div>\n      <h3>สังเกตว่าพนักงานใช้งานระบบอย่างไรระหว่างการผลิตจริง</h3>\n      <p>ดูพนักงานจริงใช้เทอร์มินัล MES บนพื้นที่ผลิต — ดูอินเทอร์เฟซที่พวกเขาใช้ วิธีรายงานการผลิต และวิธีจัดการกับข้อยกเว้น</p>\n    </div>\n\n    <div class="ftm-out-card">\n      <div class="ftm-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg>\n      </div>\n      <h3>ถามคำถามโดยตรงกับพนักงานโรงงานเกี่ยวกับประสบการณ์ของพวกเขา</h3>\n      <p>ไม่มีฟิลเตอร์จากฝ่ายขาย พูดคุยโดยตรงกับผู้จัดการโรงงาน ทีม IT และพนักงานหน้างาน เกี่ยวกับสิ่งที่ได้ผล สิ่งที่ไม่ได้ผล และสิ่งที่พวกเขาจะเปลี่ยน</p>\n    </div>\n\n    <div class="ftm-out-card">\n      <div class="ftm-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><rect x="4" y="2" width="16" height="20" rx="2"/><line x1="8" y1="6" x2="16" y2="6"/><line x1="8" y1="10" x2="16" y2="10"/><line x1="8" y1="14" x2="12" y2="14"/></svg>\n      </div>\n      <h3>เข้าใจข้อกำหนดจริงสำหรับการติดตั้ง MES ของคุณเอง</h3>\n      <p>โครงสร้างพื้นฐาน เครือข่าย การฝึกอบรมพนักงาน การจัดการการเปลี่ยนแปลง — เรียนรู้ว่าต้องใช้อะไรบ้างจากคนที่ทำมาแล้ว</p>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda — Factory Tour MES (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda — Factory Tour MES (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda — Factory Tour MES (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-agen-section">\n  <div class="ftm-agen-inner">\n    <span class="ftm-agen-label">กำหนดการทัวร์</span>\n    <h2 class="ftm-agen-title">การเยี่ยมชมที่มีโครงสร้าง — ไม่ใช่ทัวร์ขายของ</h2>\n    <p class="ftm-agen-subtitle">ทุกจุดถูกออกแบบตามสิ่งที่คุณต้องประเมิน — ไม่ใช่สิ่งที่เราอยากโชว์</p>\n  </div>\n  <div class="ftm-agen-timeline">\n    \n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">10:00 – 10:30</div>\n      <div class="ftm-agen-content">\n        <h3>ลงทะเบียนและบรรยายสรุปด้านความปลอดภัย</h3>\n        <p>ต้อนรับ แนะนำตัว แจกอุปกรณ์ความปลอดภัย และภาพรวมเส้นทางการติดตั้ง MES ของโรงงาน</p>\n      </div>\n    </div>\n\n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">10:30 – 11:30</div>\n      <div class="ftm-agen-content">\n        <h3>ทัวร์พื้นที่ผลิต — สายการผลิตที่ใช้ MES จริง</h3>\n        <p>เดินชมสายการผลิตและดู DigiWin MES ทำงานบนเวิร์กสเตชันจริง สังเกตพนักงานรายงานการผลิต ดูการเก็บข้อมูลจากเครื่องจักร และวิธีจัดการข้อยกเว้นแบบเรียลไทม์</p>\n      </div>\n    </div>\n\n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">11:30 – 12:00</div>\n      <div class="ftm-agen-content">\n        <h3>ห้องแดชบอร์ดผู้บริหาร — ข้อมูลเรียลไทม์ในการใช้งานจริง</h3>\n        <p>ดูว่าข้อมูลที่คุณเพิ่งเห็นการเก็บบนพื้นที่ผลิตปรากฏบนแดชบอร์ดผู้บริหารอย่างไร — OEE ความคืบหน้าการผลิต ตัวชี้วัดคุณภาพ อัปเดตแบบเรียลไทม์ทั้งหมด</p>\n      </div>\n    </div>\n\n    <div class="ftm-agen-item ftm-agen-item--break">\n      <div class="ftm-agen-time">12:00 – 13:00</div>\n      <div class="ftm-agen-content">\n        <h3>อาหารกลางวันและสร้างเครือข่ายกับผู้บริหารโรงงาน</h3>\n        \n      </div>\n    </div>\n\n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">13:00 – 14:00</div>\n      <div class="ftm-agen-content">\n        <h3>ถาม-ตอบกับผู้จัดการโรงงานและทีม IT</h3>\n        <p>เปิดให้ถามทุกเรื่อง — ระยะเวลาการติดตั้ง ความท้าทายที่เจอ การยอมรับของพนักงาน การเชื่อมต่อกับระบบเดิม และค่าใช้จ่ายจริง</p>\n      </div>\n    </div>\n\n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">14:00 – 14:45</div>\n      <div class="ftm-agen-content">\n        <h3>บทเรียนจากการติดตั้ง — สิ่งที่พวกเขาจะทำต่างออกไป</h3>\n        <p>ทีมโรงงานแชร์ประสบการณ์จริงอย่างตรงไปตรงมา — สิ่งที่ทำได้ดี สิ่งที่เซอร์ไพรส์ และคำแนะนำสำหรับคนที่กำลังจะเริ่มเส้นทางเดียวกัน</p>\n      </div>\n    </div>\n\n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">14:45 – 15:00</div>\n      <div class="ftm-agen-content">\n        <h3>สรุปและขั้นตอนถัดไป</h3>\n        <p>สรุปประเด็นสำคัญ คำถามรายบุคคล และคำแนะนำขั้นตอนถัดไปสำหรับการประเมิน MES สำหรับโรงงานของคุณ</p>\n      </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Personas — Factory Tour MES (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Personas — Factory Tour MES (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Personas — Factory Tour MES (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-per-section">\n  <div class="ftm-per-inner">\n    <span class="ftm-per-label">งานนี้เหมาะกับใคร</span>\n    <h2 class="ftm-per-title">การเยี่ยมชมครั้งนี้เหมาะกับคุณหรือไม่?</h2>\n    <div class="ftm-per-grid">\n      \n    <div class="ftm-per-card">\n      <div class="ftm-per-accent"></div>\n      <div class="ftm-per-body">\n        <div class="ftm-per-role">เจ้าของโรงงาน / กรรมการผู้จัดการ</div>\n        <span class="ftm-per-size">กำลังพิจารณาลงทุน MES</span>\n        <p class="ftm-per-desc">คุณเคยดูพรีเซนเทชันและอ่านโบรชัวร์มาแล้ว แต่คุณต้องเห็น MES ทำงานในโรงงานจริงก่อนอนุมัติงบประมาณ คุณอยากรู้ว่าการลงทุนนี้หน้าตาเป็นอย่างไรบนพื้นที่ผลิตจริง — ไม่ใช่แค่บนสไลด์</p>\n        <p class="ftm-per-quote">"ผมต้องเห็นระบบทำงานจริงในโรงงานก่อนจะอนุมัติงบ"</p>\n      </div>\n    </div>\n\n    <div class="ftm-per-card">\n      <div class="ftm-per-accent"></div>\n      <div class="ftm-per-body">\n        <div class="ftm-per-role">ผู้จัดการฝ่ายปฏิบัติการ / IT</div>\n        <span class="ftm-per-size">กำลังประเมินโซลูชัน MES</span>\n        <p class="ftm-per-desc">คุณจะเป็นคนที่ติดตั้งและดูแลระบบ คุณต้องเข้าใจความเป็นจริงในทางปฏิบัติ — ข้อกำหนดเครือข่าย การฝึกอบรมพนักงาน ความซับซ้อนในการเชื่อมต่อ และประสบการณ์การใช้ MES ในการผลิตจริงในแต่ละวัน</p>\n        <p class="ftm-per-quote">"ผมอยากเข้าใจความจริงของ MES ในทางปฏิบัติ — ไม่ใช่แค่คำพูดของฝ่ายขาย"</p>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof — Factory Tour MES (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof — Factory Tour MES (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof — Factory Tour MES (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-prf-section">\n  <div class="ftm-prf-inner">\n    <span class="ftm-prf-label">ทำไมต้องงาน DigiWin</span>\n    <h2 class="ftm-prf-title">เรียนรู้จากทีมที่ทำมาแล้วกว่า 100+ ครั้ง</h2>\n    <div class="ftm-prf-stats-bar">\n      \n    <div class="ftm-prf-stat">\n      <div class="ftm-prf-stat-value">100+</div>\n      <div class="ftm-prf-stat-label">ติดตั้งในประเทศไทย</div>\n    </div>\n\n    <div class="ftm-prf-stat">\n      <div class="ftm-prf-stat-value">44</div>\n      <div class="ftm-prf-stat-label">ปีเชี่ยวชาญด้านการผลิต</div>\n    </div>\n\n    <div class="ftm-prf-stat">\n      <div class="ftm-prf-stat-value">95%</div>\n      <div class="ftm-prf-stat-label">อัตราการต่อสัญญาบำรุงรักษา</div>\n    </div>\n\n    <div class="ftm-prf-stat">\n      <div class="ftm-prf-stat-value">50+</div>\n      <div class="ftm-prf-stat-label">ทีมงานคนไทย</div>\n    </div>\n    </div>\n    <p class="ftm-prf-text">DigiWin ช่วยผู้ผลิตไทยดิจิทัลไลซ์พื้นที่ผลิตมา 8 ปี การเยี่ยมชมโรงงานครั้งนี้ให้คุณเข้าถึงการติดตั้งจริง — ระบบเดียวกัน ทีมเดียวกัน และแนวทางเดียวกันที่เรานำไปใช้กับทุกโปรเจกต์ MES</p>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics — Factory Tour MES (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics — Factory Tour MES (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics — Factory Tour MES (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-log-section">\n  <div class="ftm-log-inner">\n    <span class="ftm-log-label">รายละเอียดปฏิบัติ</span>\n    <h2 class="ftm-log-title">ทุกอย่างที่คุณต้องรู้</h2>\n    <div class="ftm-log-grid">\n      \n    <div class="ftm-log-item">\n      <div class="ftm-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2=