iv class="ftm-log-item-label">ภาษา</div>\n        <div class="ftm-log-item-value">ไทย</div>\n      </div>\n    </div>\n\n    <div class="ftm-log-item">\n      <div class="ftm-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>\n      </div>\n      <div>\n        <div class="ftm-log-item-label">การแต่งกาย</div>\n        <div class="ftm-log-item-value">รองเท้าหุ้มส้นเท่านั้น อุปกรณ์ความปลอดภัยจัดเตรียมให้ที่โรงงาน</div>\n      </div>\n    </div>\n\n    <div class="ftm-log-item">\n      <div class="ftm-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><path d="M23 19a2 2 0 01-2 2H3a2 2 0 01-2-2V8a2 2 0 012-2h4l2-3h6l2 3h4a2 2 0 012 2z"/><circle cx="12" cy="13" r="4"/></svg>\n      </div>\n      <div>\n        <div class="ftm-log-item-label">การถ่ายภาพ</div>\n        <div class="ftm-log-item-value">อาจมีข้อจำกัด จะแจ้งรายละเอียดในช่วงบรรยายสรุปด้านความปลอดภัย</div>\n      </div>\n    </div>\n\n    <div class="ftm-log-item">\n      <div class="ftm-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><rect x="1" y="3" width="15" height="13"/><polygon points="16 8 20 8 23 11 23 16 16 16 16 8"/><circle cx="5.5" cy="18.5" r="2.5"/><circle cx="18.5" cy="18.5" r="2.5"/></svg>\n      </div>\n      <div>\n        <div class="ftm-log-item-label">การเดินทาง</div>\n        <div class="ftm-log-item-value">มีรถรับส่งจากกรุงเทพฯ — จะแจ้งรายละเอียดหลังลงทะเบียน</div>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Register CTA — Factory Tour MES (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Register CTA — Factory Tour MES (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Register CTA — Factory Tour MES (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-reg-section">\n  <h2>ลงทะเบียนเยี่ยมชม</h2>\n  <p class="ftm-reg-meta">วันพฤหัสบดีที่ 8 พฤษภาคม 2026 &middot; EEC Industrial Zone &middot; จำกัด 20 ท่าน</p>\n  \n  <a href="/th/demo/" class="ftm-reg-cta">\n    ลงทะเบียนเยี่ยมชม\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n  </a>\n  <p class="ftm-reg-secondary">มาวันนี้ไม่ได้? <a href="/th/demo/">ลงทะเบียนแสดงความสนใจ</a> and we\'ll notify you of the next session.</p>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Events — Factory Tour MES (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Events — Factory Tour MES (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Events — Factory Tour MES (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-rel-section">\n  <div class="ftm-rel-inner">\n    <span class="ftm-rel-label">กิจกรรมที่กำลังจะมาถึง</span>\n    <h2 class="ftm-rel-title">เรียนรู้ต่อเนื่อง</h2>\n    <div class="ftm-rel-grid">\n      \n    <div class="ftm-rel-card">\n      <div class="ftm-rel-card-border" style="background:#15803d"></div>\n      <div class="ftm-rel-card-body">\n        <span class="ftm-rel-badge" style="color:#15803d;background:rgba(21,128,61,0.12)">Workshop</span>\n        <h3>BOI Compliance Workshop: Production-Level Reconciliation That Passes Every Audit</h3>\n        <div class="ftm-rel-meta">\n          <div class="ftm-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            March 15, 2026\n          </div>\n          <div class="ftm-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            Bangkok, Thailand\n          </div>\n        </div>\n        <a href="/news/events/boi-compliance-workshop/" class="ftm-rel-link" style="color:#15803d">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n\n    <div class="ftm-rel-card">\n      <div class="ftm-rel-card-border" style="background:#6d28d9"></div>\n      <div class="ftm-rel-card-body">\n        <span class="ftm-rel-badge" style="color:#6d28d9;background:rgba(109,40,217,0.12)">Trade Show</span>\n        <h3>Manufacturing Expo 2026: DigiWin Thailand Booth</h3>\n        <div class="ftm-rel-meta">\n          <div class="ftm-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            May 20–22, 2026\n          </div>\n          <div class="ftm-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            BITEC, Bangkok\n          </div>\n        </div>\n        <a href="/news/events/manufacturing-expo-2026/" class="ftm-rel-link" style="color:#6d28d9">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n\n    <div class="ftm-rel-card">\n      <div class="ftm-rel-card-border" style="background:#0369a1"></div>\n      <div class="ftm-rel-card-body">\n        <span class="ftm-rel-badge" style="color:#0369a1;background:rgba(3,105,161,0.12)">Seminar</span>\n        <h3>Production Transparency: From Paper Reports to Real-Time Dashboards</h3>\n        <div class="ftm-rel-meta">\n          <div class="ftm-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            April 10, 2026\n          </div>\n          <div class="ftm-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            Bangkok, Thailand\n          </div>\n        </div>\n        <a href="/news/events/production-transparency-seminar/" class="ftm-rel-link" style="color:#0369a1">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
